require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/driver_functions.php';requireAuth();enforceModuleAccess('drivers');$id=(int)($_GET['id']??$_POST['id']??0);$driver=getDriverById($id);if(!$driver)redirect('modules/drivers/index.php');if($_SERVER['REQUEST_METHOD']==='POST'&&verifyCsrfToken((string)($_POST['csrf_token']??''))){getDb()->prepare('UPDATE drivers SET deleted_at=NOW(),status="Inactive" WHERE id=?')->execute([$id]);logActivity('Driver archived','Driver #'.$id);setFlash('success','Driver archived.');redirect('modules/drivers/index.php');}$pageTitle='Archive driver';require ROOT_PATH.'/includes/header.php';?><main class="auth-shell"><form class="auth-card card" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><h2>Archive driver?</h2><p><?=e($driver['full_name'])?> will be removed from availability and future assignments.</p><button class="btn btn-danger">Archive driver</button><a class="auth-link" href="view.php?id=<?=$id?>">Cancel</a></form></main><?php require ROOT_PATH.'/includes/footer.php';?>
